    <tr><td class="tm">NOME</td><td class="tv">VALOR UNIDADE</td><td class="tref">MIN</td><td class="tref">MAX</td><td><span class="badge bc"><span class="dot"></span>Critico</span></td><td class="tobs">OBSERVACAO</td></tr>
    
